mapper.select:
SELECT p.id AS partyId, p.product_id AS productId, sp.service_name AS productName, sp.thumbnail_url AS thumbnailUrl, u.nickname AS hostNickname, p.capacity AS totalCapacity, p.current_member_count AS currentMemberCount, (p.capacity - p.current_member_count) AS remainingSeatCount, p.price_per_member_snapshot AS monthlyPaymentAmount, ( SELECT pc.billing_due_at FROM party_cycle pc WHERE pc.party_id = p.id ORDER BY pc.cycle_no DESC, pc.id DESC LIMIT 1 ) AS nextPaymentDate, '파티원 참여' AS joinButtonLabel FROM party p INNER JOIN sub_product sp ON sp.id = p.product_id INNER JOIN users u ON u.id = p.host_user_id WHERE p.recruit_status = 'RECRUITING' AND p.vacancy_type = 'MEMBER' AND p.current_member_count < p.capacity
AND p.product_id = #{productId}
ORDER BY (p.capacity - p.current_member_count) ASC, p.created_at ASC
